import OpenAI from "openai";

const client = new OpenAI();

const threadId = process.env.THREAD_ID;
const assistantId = process.env.ASSISTANT_ID;
if (!threadId || !assistantId) throw new Error("THREAD_ID and ASSISTANT_ID are required");

const additionalInstructions = process.env.ADDITIONAL_INSTRUCTIONS || undefined;
const maxCompletionTokens = process.env.MAX_COMPLETION_TOKENS ? parseInt(process.env.MAX_COMPLETION_TOKENS) : undefined;

const run = await client.beta.threads.runs.createAndPoll(threadId, {
  assistant_id: assistantId,
  ...(additionalInstructions && { additional_instructions: additionalInstructions }),
  ...(maxCompletionTokens && { max_completion_tokens: maxCompletionTokens }),
});

if (run.status === "completed") {
  const messages = await client.beta.threads.messages.list(threadId, { order: "desc", limit: 1 });
  const response = messages.data[0].content[0].text.value;
  console.log(JSON.stringify({
    runId: run.id,
    status: run.status,
    response,
    usage: run.usage ? {
      promptTokens: run.usage.prompt_tokens,
      completionTokens: run.usage.completion_tokens,
      totalTokens: run.usage.total_tokens,
    } : null,
  }, null, 2));
} else if (run.status === "requires_action") {
  const toolCalls = run.required_action.submit_tool_outputs.tool_calls;
  console.log(JSON.stringify({
    runId: run.id,
    status: run.status,
    toolCalls: toolCalls.map(tc => ({
      id: tc.id,
      function: tc.function.name,
      arguments: JSON.parse(tc.function.arguments),
    })),
  }, null, 2));
} else {
  console.error(JSON.stringify({
    runId: run.id,
    status: run.status,
    error: run.last_error,
  }, null, 2));
  process.exit(1);
}

import OpenAI from "openai";

const client = new OpenAI();

const threadId = process.env.THREAD_ID;
const assistantId = process.env.ASSISTANT_ID;
if (!threadId || !assistantId) throw new Error("THREAD_ID and ASSISTANT_ID are required");

const stream = client.beta.threads.runs.stream(threadId, {
  assistant_id: assistantId,
});

let runId = null;
for await (const event of stream) {
  if (event.event === "thread.run.created") {
    runId = event.data.id;
    console.error(`Run started: ${runId}`);
  }
  if (event.event === "thread.message.delta") {
    const content = event.data.delta.content?.[0]?.text?.value || "";
    process.stdout.write(content);
  }
  if (event.event === "thread.run.completed") {
    console.error(`\nRun completed: ${event.data.id}`);
  }
  if (event.event === "thread.run.failed") {
    console.error(`\nRun failed: ${event.data.last_error?.message}`);
    process.exit(1);
  }
}
console.log();
